import { z } from 'zod';

export const envSchema = z.object({
  CLOUDFLARE_ACCOUNT_ID: z.string().describe('Cloudflare account ID associated with your GoldShore organization. This must be set on every service.'),
  CLOUDFLARE_API_TOKEN: z.string().describe('API token with permissions to deploy Workers, manage KV, R2, D1, Queues and Pages for the given account.'),
  CLOUDFLARE_ZONE_ID: z.string().describe('Zone ID for the DNS zone (e.g., goldshore.org). Used by Workers or Pages when managing DNS or retrieving zone context.'),
  CLOUDFLARE_ENV: z.string().describe('Deployment environment name (dev, staging, prod). Aligns with GitHub environment names, Terraform workspaces and Cloudflare bindings.'),
  CLOUDFLARE_PROJECT: z.string().describe('Identifier for the specific project or microservice (goldshore-api, goldshore-admin, goldshore-web, goldshore-gateway).'),
  CLOUDFLARE_BASE_DOMAIN: z.string().describe('Base domain name used across all projects (e.g., goldshore.org).'),
  CLOUDFLARE_PUBLIC_URL: z.string().describe('Public URL for the service (e.g., https://api.goldshore.org).'),
  CF_ACCESS_TEAM_DOMAIN: z.string().describe('Team domain for Cloudflare Access (e.g., goldshore.cloudflareaccess.com).'),
  CF_ACCESS_AUD: z.string().describe('Audience (AUD) claim used to verify Access JWTs. Derived from the Access application settings.'),
  CF_ACCESS_JWKS_URL: z.string().describe('JWKS endpoint for verifying Access JWT signatures. Typically https://<team>.cloudflareaccess.com/cdn-cgi/access/certs.'),
  CF_ACCESS_POLICY_ID: z.string().optional().describe('Specific Access policy ID to enforce role-based authentication. Optional but recommended for strict gating.'),
  INTERNAL_API_BASE_URL: z.string().describe('Base URL for internal API calls between services. For example, goldshore-api uses this to call other microservices.'),
  INTERNAL_API_KEY: z.string().describe('Shared secret used to authenticate internal API calls. Should be rotated infrequently and stored securely.'),
  INTERNAL_GW_URL: z.string().describe('URL of the gateway worker for inter-service routing. Typically https://gateway.goldshore.org.'),
  INTERNAL_GW_TOKEN: z.string().describe('Gateway-level authentication token for internal service calls.'),
  KV_NAMESPACE_ID: z.string().describe('Namespace ID for Cloudflare KV used by the service. Each project may have multiple KV namespaces; this should reference the primary one.'),
  R2_BUCKET_ID: z.string().describe('Bucket name or ID for Cloudflare R2 used by the service.'),
  QUEUE_NAMESPACE_ID: z.string().describe('Queue namespace ID for Cloudflare Queues.'),
  DURABLE_OBJECTS_NAMESPACE_ID: z.string().describe('Namespace ID for Durable Objects used by the service.'),
  JWT_SECRET: z.string().describe('Secret used to sign JWTs generated by the application. Must be consistent across services that issue and verify tokens.'),
  SESSION_SECRET: z.string().describe('Secret used for encrypting and signing session cookies. Must be consistent across services when sharing sessions.'),
  ENCRYPTION_KEY: z.string().describe('Key used for symmetric encryption of sensitive payloads (e.g., user data stored in KV or R2).'),
  SIGNING_KEY: z.string().describe('Key used for signing internal messages, webhooks and other operations requiring integrity checks.'),
  VITE_PUBLIC_BASE_URL: z.string().describe('Public base URL used by frontend builds in Vite (e.g., https://goldshore.org).'),
  VITE_API_URL: z.string().describe('API endpoint used by the frontend for calling the API service (e.g., https://api.goldshore.org).'),
  VITE_GATEWAY_URL: z.string().describe('URL of the gateway used by the frontend for AI and routing (e.g., https://gateway.goldshore.org).'),
  VITE_APP_ENV: z.string().describe('Frontend environment variable mirroring CLOUDFLARE_ENV.'),
  VITE_ASSETS_BASE: z.string().describe('Base path for static assets (e.g., /assets/).'),
  LOG_LEVEL: z.string().describe('Logging verbosity for the service (debug, info, warn, error).'),
  LOG_SERVICE_NAME: z.string().describe('Name of the service used in structured logs (e.g., goldshore-api).'),
  AI_LOG_ENDPOINT: z.string().optional().describe('Optional endpoint for AI or agent logs (e.g., APM or external logging service).'),
  AI_AGENT_NAME: z.string().optional().describe('Identifier for the AI agent when reporting logs or metrics.'),
  GSL_AI_GATEWAY_URL: z.string().describe('URL of the GoldShore AI Gateway. This is used by services performing AI calls.'),
  GSL_AI_GATEWAY_KEY: z.string().describe('API key for authenticating calls to the AI Gateway.'),
  GSL_DEFAULT_MODEL: z.string().describe('Default model identifier used by the AI Gateway for text generation.'),
  GSL_EMBEDDING_MODEL: z.string().describe('Model identifier used for embedding generation in RAG workflows.'),
  GSL_RAG_INDEX: z.string().describe('Name of the RAG index to use for vector search.'),
  TF_STATE_BUCKET: z.string().describe('Name of the bucket used by Terraform to store state files.'),
  TF_STATE_KEY: z.string().describe('Key path within the state bucket for the current service.'),
  TF_STATE_REGION: z.string().describe('Region or provider location for the Terraform state bucket.'),
  TF_VAR_environment: z.string().describe('Environment variable passed to Terraform to set the environment context.'),
  TF_VAR_project: z.string().describe('Project name passed to Terraform to identify resources.'),
  PRIMARY_ROUTE: z.string().describe('Primary route pattern for the service (e.g., api.goldshore.org/*).'),
  FALLBACK_ROUTE: z.string().describe('Fallback route for SPA or static sites.'),
  ERROR_PAGE_PATH: z.string().describe('Path to a custom error page or template used for unhandled errors.'),
  BUILD_OUTPUT_DIR: z.string().describe('Directory where build artifacts are output (e.g., dist/).'),
  ASSET_MANIFEST_PATH: z.string().describe('Path to the manifest file generated by the build tooling.'),
  API_VERSION: z.string().optional().describe('API version string used by the goldshore-api service.'),
  API_PUBLIC_URL: z.string().optional().describe('Public URL for the API (should mirror CLOUDFLARE_PUBLIC_URL when CLOUDFLARE_PROJECT=goldshore-api).'),
  DATABASE_URL: z.string().optional().describe('Database connection string (if the service uses an external database).'),
  ADMIN_PUBLIC_URL: z.string().optional().describe('Public URL for the admin application (should mirror CLOUDFLARE_PUBLIC_URL when CLOUDFLARE_PROJECT=goldshore-admin).'),
  ADMIN_AUTH_REQUIRED: z.string().optional().describe('Boolean flag indicating if admin pages require authentication.'),
  WEB_PUBLIC_URL: z.string().optional().describe('Public URL for the web application (should mirror CLOUDFLARE_PUBLIC_URL when CLOUDFLARE_PROJECT=goldshore-web).'),
  WEB_THEME_MODE: z.string().optional().describe('Default theme mode for the web application (light, dark, or auto).'),
  WEB_CDN_BASE: z.string().optional().describe('Base URL for serving CDN-hosted assets (e.g., https://cdn.goldshore.org).'),
  GATEWAY_PUBLIC_URL: z.string().optional().describe('Public URL for the gateway service (should mirror CLOUDFLARE_PUBLIC_URL when CLOUDFLARE_PROJECT=goldshore-gateway).'),
  GATEWAY_ROUTING_TABLE: z.string().optional().describe('JSON or path to configuration that defines routing rules for the gateway.'),
});

export type Env = z.infer<typeof envSchema>;
